# POST — yangi foydalanuvchi
@app.route('/api/users', methods=['POST'])
def user_qoshish():
    ma_lumot = request.get_json()
    if not ma_lumot or 'isim' not in ma_lumot:
        return jsonify({"xato": "isim majburiy"}), 400

    yangi = {
        "id": len(foydalanuvchilar) + 1,
        "isim": ma_lumot['isim'],
        "xp": ma_lumot.get('xp', 0)
    }
    foydalanuvchilar.append(yangi)
    return jsonify({"muvaffaqiyat": True, "ma_lumot": yangi}), 201

# PUT — yangilash
