def user_yangilash(user_id):
    user = next((u for u in foydalanuvchilar if u['id'] == user_id), None)
    if not user:
        return jsonify({"xato": "Topilmadi"}), 404

    ma_lumot = request.get_json()
    user.update(ma_lumot)
    return jsonify({"muvaffaqiyat": True, "ma_lumot": user})

# DELETE
@app.route('/api/users/<int:user_id>', methods=['DELETE'])
def user_ochirish(user_id):
    global foydalanuvchilar
    oldingi = len(foydalanuvchilar)
    foydalanuvchilar = [u for u in foydalanuvchilar if u['id'] != user_id]
    if len(foydalanuvchilar) < oldingi:
        return jsonify({"muvaffaqiyat": True})
    return jsonify({"xato": "Topilmadi"}), 404

