def linear_search(lst, target):
    for i, val in enumerate(lst):
        if val == target:
            return i
    return -1

def binary_search(lst, target):
    l, r = 0, len(lst)-1
    while l <= r:
        mid = (l+r)//2
        if lst[mid] == target: return mid
        elif lst[mid] < target: l = mid+1
        else: r = mid-1
    return -1

