def infix_to_postfix(expr):
    precedence = {'+':1,'-':1,'*':2,'/':2}
    output, stack = [], Stack()
    for ch in expr.replace(' ',''):
        if ch.isalnum(): output.append(ch)
        elif ch == '(': stack.push(ch)
        elif ch == ')':
            while not stack.is_empty() and stack.peek()!='(': output.append(stack.pop())
            stack.pop()
        else:
            while not stack.is_empty() and stack.peek()!='(' and precedence.get(stack.peek(),0)>=precedence[ch]:
                output.append(stack.pop())
            stack.push(ch)
    while not stack.is_empty(): output.append(stack.pop())
    return ' '.join(output)

def find_middle(head):
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
    return slow

def has_cycle(head):
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow == fast: return True
    return False

