## Tree (Daraxt)

Tree — ierarxik ma'lumot tuzilmasi. **Root** (ildiz) tepada, **leaf** (barg) nodlar pastda.

```python
class TreeNode:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

# Binary Search Tree (BST)
class BST:
    def __init__(self):
        self.root = None

    def insert(self, val):
        self.root = self._insert(self.root, val)

    def _insert(self, node, val):
        if not node:
            return TreeNode(val)
        if val < node.val:
            node.left = self._insert(node.left, val)
        elif val > node.val:
            node.right = self._insert(node.right, val)
        return node

    def search(self, val):
        return self._search(self.root, val)

    def _search(self, node, val):
        if not node or node.val == val:
            return node
        if val < node.val:
            return self._search(node.left, val)
        return self._search(node.right, val)

    # Inorder traversal (tartiblangan chiqaradi)
    def inorder(self, node, result=[]):
        if node:
            self.inorder(node.left, result)
            result.append(node.val)
            self.inorder(node.right, result)
        return result

bst = BST()
for val in [5,3,7,1,4,6,8]:
    bst.insert(val)
print(bst.inorder(bst.root, []))  # [1,3,4,5,6,7,8]
print(bst.search(4).val)          # 4
```

## Graph (Graf)

Graph — nodlar va ularni bog'lovchi qirralardan iborat tuzilma.

```python
# Adjacency List bilan graph
class Graph:
    def __init__(self):
        self.graph = {}

    def add_vertex(self, v):
        self.graph[v] = []

    def add_edge(self, u, v):
        self.graph[u].append(v)
        self.graph[v].append(u)  # yo'nalishsiz

    # BFS — kenglik bo'yicha qidirish
    def bfs(self, start):
        visited = set()
        queue = [start]
        visited.add(start)
        result = []
        while queue:
            node = queue.pop(0)
            result.append(node)
            for neighbor in self.graph[node]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return result

    # DFS — chuqurlik bo'yicha qidirish
    def dfs(self, start, visited=None):
        if visited is None: visited = set()
        visited.add(start)
        result = [start]
        for neighbor in self.graph[start]:
            if neighbor not in visited:
                result.extend(self.dfs(neighbor, visited))
        return result

g = Graph()
for v in ['A','B','C','D','E']: g.add_vertex(v)
g.add_edge('A','B'); g.add_edge('A','C'); g.add_edge('B','D'); g.add_edge('C','E')
print(g.bfs('A'))  # ['A','B','C','D','E']
print(g.dfs('A'))  # ['A','B','D','C','E']
```

Tree va Graph — eng keng qo'llaniladigan tuzilmalar: fayl tizimi (tree), ijtimoiy tarmoq (graph), yo'l topish (BFS/DFS).

