import argparse

def count_file(args):
    try:
        with open(args.file, encoding='utf-8') as f:
            content = f.read()
        lines = content.count('\n')
        words = len(content.split())
        chars = len(content)
        if args.w and args.c:
            print(f"Qatorlar: {lines}, So'zlar: {words}, Belgilar: {chars}")
        elif args.w:
            print(f"Qatorlar: {lines}, So'zlar: {words}")
        elif args.c:
            print(f"Qatorlar: {lines}, Belgilar: {chars}")
        else:
            print(f"Qatorlar: {lines}")
    except FileNotFoundError:
        print(f"Xato: {args.file} topilmadi")

def search_file(args):
    try:
        with open(args.file, encoding='utf-8') as f:
            lines = f.readlines()
        found = 0
        for i, line in enumerate(lines, 1):
            haystack = line if args.case_sensitive else line.lower()
            needle = args.pattern if args.case_sensitive else args.pattern.lower()
            if needle in haystack:
                print(f"{i}-qator: {line.strip()}")
                found += 1
        if found == 0:
            print("Topilmadi")
    except FileNotFoundError:
        print(f"Xato: {args.file} topilmadi")

def replace_text(args):
    try:
        with open(args.file, encoding='utf-8') as f:
            content = f.read()
        count = content.count(args.old)
        new_content = content.replace(args.old, args.new)
        out = args.output if args.output else args.file
        with open(out, 'w', encoding='utf-8') as f:
            f.write(new_content)
        print(f"Almashtirildi: {count} marta -> {out}")
    except FileNotFoundError:
        print(f"Xato: {args.file} topilmadi")

def main():
    parser = argparse.ArgumentParser(description='Fayl boshqarish vositasi')
