from typing import List, Optional, Dict
from dataclasses import dataclass

@dataclass
class Book:
    isbn: str
    title: str
    author: str
    year: int
    available: bool = True

class Library:
    def __init__(self) -> None:
        self._books: Dict[str, Book] = {}
    def add_book(self, book: Book) -> None:
        self._books[book.isbn] = book
    def find_by_author(self, author: str) -> List[Book]:
        return [b for b in self._books.values() if author.lower() in b.author.lower()]
    def find_by_title(self, title: str) -> Optional[Book]:
        for book in self._books.values():
            if title.lower() in book.title.lower():
                return book
        return None
    def get_available(self) -> List[Book]:
        return [b for b in self._books.values() if b.available]
    def checkout(self, isbn: str) -> bool:
        book = self._books.get(isbn)
        if book and book.available:
            book.available = False
            return True
        return False

if __name__ == '__main__':
    lib = Library()
    books = [
        Book('978-1', 'Python Asoslari', 'Guido Van Rossum', 2020),
        Book('978-2', 'Python Professional', 'Guido Van Rossum', 2022),
        Book('978-3', 'Django Framework', 'Adrian Holovaty', 2021),
