Design Pattern (loyihalash namunasi) — dasturlashda tez-tez uchraydigan muammolarga sinab ko'rilgan, qayta ishlatiladigan yechimlar. Gang of Four (GoF) kitobidan kelgan 23 ta asosiy pattern bor.

**1. SINGLETON — yagona nusxa**
Maqsad: Klass faqat bitta nusxada bo'lishini ta'minlash (ma'lumotlar bazasi ulanishi, logger, konfiguratsiya).

```python
class DatabaseConnection:
    _instance = None
    _connection = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            print('Yangi ulanish yaratildi')
        return cls._instance

    def connect(self, url: str):
        self._connection = url
        print(f'Ulandi: {url}')

    def query(self, sql: str):
        print(f'SQL: {sql}')

# Test
db1 = DatabaseConnection()
db2 = DatabaseConnection()
print(db1 is db2)  # True — bir xil obyekt
db1.connect('postgresql://localhost/mydb')
db2.query('SELECT * FROM users')  # bir xil ulanish
```

**Thread-safe Singleton:**
```python
import threading

class SafeSingleton:
    _instance = None
    _lock = threading.Lock()

    def __new__(cls):
        with cls._lock:
            if cls._instance is None:
                cls._instance = super().__new__(cls)
        return cls._instance
```

**2. FACTORY — obyekt yaratish fabrikasi**
Maqsad: Obyekt yaratish mantig'ini ajratish — yaratuvchi klass qaysi konkret klass yaratilishini bilmaydi.

```python
from abc import ABC, abstractmethod

class Notification(ABC):
    @abstractmethod
    def send(self, message: str, recipient: str) -> bool:
        pass

class EmailNotification(Notification):
    def send(self, message: str, recipient: str) -> bool:
        print(f'Email -> {recipient}: {message}')
        return True

class SMSNotification(Notification):
    def send(self, message: str, recipient: str) -> bool:
        print(f'SMS -> {recipient}: {message}')
        return True

class TelegramNotification(Notification):
    def send(self, message: str, recipient: str) -> bool:
        print(f'Telegram -> {recipient}: {message}')
        return True

class NotificationFactory:
    _registry = {
        'email': EmailNotification,
        'sms': SMSNotification,
        'telegram': TelegramNotification
    }

    @classmethod
    def create(cls, notification_type: str) -> Notification:
        klass = cls._registry.get(notification_type.lower())
        if not klass:
            raise ValueError(f"Noma'lum tur: {notification_type}")
        return klass()

    @classmethod
    def register(cls, name: str, klass):
        cls._registry[name] = klass

# Ishlatish
notifier = NotificationFactory.create('email')
notifier.send('Xush kelibsiz!', 'ali@example.com')

telegram = NotificationFactory.create('telegram')
telegram.send('Yangi xabar', '@ali_user')
```

**3. OBSERVER — hodisalar kuzatuvchisi**
Maqsad: Bir obyektdagi o'zgarish ko'p kuzatuvchilarga avtomatik xabar berish (event system).

```python
from typing import List, Protocol

class Observer(Protocol):
    def update(self, event: str, data: dict) -> None: ...

class EventManager:
    def __init__(self):
        self._listeners: dict = {}

    def subscribe(self, event: str, observer) -> None:
        if event not in self._listeners:
            self._listeners[event] = []
        self._listeners[event].append(observer)

    def unsubscribe(self, event: str, observer) -> None:
        if event in self._listeners:
            self._listeners[event].remove(observer)

    def notify(self, event: str, data: dict) -> None:
        for observer in self._listeners.get(event, []):
            observer.update(event, data)

class UserService:
    def __init__(self):
        self.events = EventManager()

    def register(self, username: str, email: str):
        user = {'username': username, 'email': email}
        self.events.notify('user_registered', user)
        return user

    def delete(self, username: str):
        self.events.notify('user_deleted', {'username': username})

class WelcomeEmailSender:
    def update(self, event: str, data: dict):
        if event == 'user_registered':
            print(f"Xush kelibsiz emaili yuborildi: {data['email']}")

class ActivityLogger:
    def update(self, event: str, data: dict):
        print(f"LOG [{event}]: {data}")

class AnalyticsTracker:
    def update(self, event: str, data: dict):
        print(f"Analytics: {event} event kuzatildi")

# Ishlatish
service = UserService()
service.events.subscribe('user_registered', WelcomeEmailSender())
service.events.subscribe('user_registered', ActivityLogger())
service.events.subscribe('user_registered', AnalyticsTracker())
service.events.subscribe('user_deleted', ActivityLogger())

service.register('ali_valiyev', 'ali@example.com')
# Chiqaradi:
# Xush kelibsiz emaili yuborildi: ali@example.com
# LOG [user_registered]: {'username': 'ali_valiyev', 'email': 'ali@example.com'}
# Analytics: user_registered event kuzatildi
```

