from abc import ABC, abstractmethod
import threading

class AppConfig:
    _instance = None
    _lock = threading.Lock()
    def __new__(cls):
        with cls._lock:
            if cls._instance is None:
                cls._instance = super().__new__(cls)
                cls._instance.db_url = 'postgresql://localhost/shop'
                cls._instance.debug = False
                cls._instance.lang = 'uz'
        return cls._instance

class PaymentMethod(ABC):
    @abstractmethod
    def pay(self, amount: float, order_id: str) -> bool:
        pass

class PaymePayment(PaymentMethod):
    def pay(self, amount, order_id):
        print(f'Payme — buyurtma #{order_id} uchun {amount} so\'m')
        return True

class ClickPayment(PaymentMethod):
    def pay(self, amount, order_id):
        print(f'Click — buyurtma #{order_id} uchun {amount} so\'m')
        return True

class UzcardPayment(PaymentMethod):
    def pay(self, amount, order_id):
        print(f'Uzcard — buyurtma #{order_id} uchun {amount} so\'m')
        return True

class PaymentFactory:
    _registry = {'payme': PaymePayment, 'click': ClickPayment, 'uzcard': UzcardPayment}
    @classmethod
    def create(cls, method: str) -> PaymentMethod:
        klass = cls._registry.get(method.lower())
        if not klass: raise ValueError(f'Noma\'lum usul: {method}')
        return klass()

class OrderObserver(ABC):
    @abstractmethod
    def update(self, event: str, data: dict) -> None: pass

class EmailObserver(OrderObserver):
    def update(self, event, data):
        if event == 'order_created':
            print(f'  Email: {data.get("email","?")} ga tasdiq yuborildi')

class SMSObserver(OrderObserver):
    def update(self, event, data):
        print(f'  SMS: {data.get("phone","?")} ga xabar yuborildi')

class WarehouseObserver(OrderObserver):
    def update(self, event, data):
        if event in ('order_created', 'order_cancelled'):
            print(f'  Warehouse: Stok yangilandi')

class OrderService:
    def __init__(self):
        self._observers = []
    def subscribe(self, obs): self._observers.append(obs)
    def unsubscribe(self, obs): self._observers.remove(obs)
    def notify(self, event, data):
