Django Views so'rovlarni qayta ishlaydi va javob qaytaradi. Class-based views (CBV) ko'p kodni avtomatik bajaradi, function-based views (FBV) esa sodda va aniq.

**Function-based views (FBV):**

```python
# users/views.py
from django.shortcuts import render, get_object_or_404, redirect
from django.http import JsonResponse, HttpResponse
from django.contrib.auth import login, logout, authenticate
from django.contrib.auth.decorators import login_required
from django.views.decorators.http import require_http_methods
from .models import User
import json

def user_list(request):
    """Barcha foydalanuvchilar ro'yxati"""
    users = User.objects.filter(is_active=True).order_by('-xp')
    return render(request, 'users/user_list.html', {'users': users})

@login_required
def user_profile(request, user_id):
    """Foydalanuvchi profili"""
    user = get_object_or_404(User, id=user_id)
    return render(request, 'users/profile.html', {'profile_user': user})

@require_http_methods(['POST'])
def login_view(request):
    """Login endpoint"""
    data = json.loads(request.body)
    user = authenticate(
        request,
        email=data.get('email'),
        password=data.get('password')
    )
    if user:
        login(request, user)
        return JsonResponse({'success': True, 'username': user.username})
    return JsonResponse({'error': 'Email yoki parol noto\'g\'ri'}, status=401)
```

**Class-based views (CBV):**

```python
from django.views import View
from django.views.generic import ListView, DetailView, CreateView, UpdateView, DeleteView
from django.urls import reverse_lazy

class UserListView(ListView):
    model = User
    template_name = 'users/user_list.html'
    context_object_name = 'users'
    paginate_by = 20

    def get_queryset(self):
        queryset = super().get_queryset().filter(is_active=True)
        direction = self.request.GET.get('direction')
        if direction:
            queryset = queryset.filter(direction=direction)
        return queryset

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['directions'] = User.DIRECTIONS
        context['total_users'] = User.objects.count()
        return context

class UserDetailView(DetailView):
    model = User
    template_name = 'users/user_detail.html'
    context_object_name = 'profile_user'

class UserCreateView(CreateView):
    model = User
    fields = ['username', 'email', 'direction']
    template_name = 'users/user_form.html'
    success_url = reverse_lazy('users:list')
```

