from fastapi import FastAPI, Depends, HTTPException, status
from fastapi.security import OAuth2PasswordBearer, OAuth2PasswordRequestForm
from jose import jwt, JWTError
from passlib.context import CryptContext
from datetime import datetime, timedelta

app = FastAPI()
SECRET_KEY = 'synapse-secret-2024'
ALGORITHM = 'HS256'

pwd_context = CryptContext(schemes=['bcrypt'], deprecated='auto')
oauth2_scheme = OAuth2PasswordBearer(tokenUrl='login')

fake_db = {
    'student': {'username': 'student', 'hashed_password': pwd_context.hash('pass123'), 'role': 'student'},
    'admin': {'username': 'admin', 'hashed_password': pwd_context.hash('admin123'), 'role': 'admin'},
}

def create_token(data: dict):
    data.update({'exp': datetime.utcnow() + timedelta(minutes=30)})
    return jwt.encode(data, SECRET_KEY, algorithm=ALGORITHM)

async def get_current_user(token: str = Depends(oauth2_scheme)):
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        username = payload.get('sub')
        user = fake_db.get(username)
        if not user:
            raise HTTPException(status_code=401, detail='Token yaroqsiz')
        return user
    except JWTError:
        raise HTTPException(status_code=401, detail='Token xato')

@app.post('/login/')
async def login(form_data: OAuth2PasswordRequestForm = Depends()):
    user = fake_db.get(form_data.username)
    if not user or not pwd_context.verify(form_data.password, user['hashed_password']):
        raise HTTPException(status_code=401, detail='Xato login yoki parol')
    token = create_token({'sub': user['username'], 'role': user['role']})
    return {'access_token': token, 'token_type': 'bearer'}

@app.get('/profile/')
async def profile(user = Depends(get_current_user)):
    return {'username': user['username'], 'role': user['role']}

@app.get('/admin/')
async def admin(user = Depends(get_current_user)):
    if user['role'] != 'admin':
        raise HTTPException(status_code=403, detail='Ruxsat yo\'q')
    return {'message': 'Admin panel'}

