    if req.operation == 'add':
        return {'result': req.a + req.b}
    elif req.operation == 'subtract':
        return {'result': req.a - req.b}
    elif req.operation == 'multiply':
        return {'result': req.a * req.b}
    elif req.operation == 'divide':
        if req.b == 0:
            raise HTTPException(status_code=400, detail='Nolga bo\'lish mumkin emas')
        return {'result': req.a / req.b}
    else:
