import boto3
from botocore.exceptions import ClientError
from typing import Optional
import os

class S3Manager:
    def __init__(self, bucket_name: str):
        self.bucket = bucket_name
        self.client = boto3.client(
            's3',
            region_name=os.getenv('AWS_REGION', 'us-east-1'),
            aws_access_key_id=os.getenv('AWS_ACCESS_KEY_ID'),
            aws_secret_access_key=os.getenv('AWS_SECRET_ACCESS_KEY')
        )

    def upload(self, local_path: str, s3_key: str) -> bool:
        try:
            self.client.upload_file(local_path, self.bucket, s3_key)
            return True
        except ClientError as e:
            print(f'Upload xato: {e}')
            return False

    def download(self, s3_key: str, local_path: str) -> bool:
        try:
            self.client.download_file(self.bucket, s3_key, local_path)
            return True
        except ClientError as e:
            print(f'Download xato: {e}')
            return False

    def delete(self, s3_key: str) -> bool:
        try:
            self.client.delete_object(Bucket=self.bucket, Key=s3_key)
            return True
        except ClientError as e:
            print(f'Delete xato: {e}')
            return False

    def get_url(self, s3_key: str, expires_in: int = 3600) -> Optional[str]:
        try:
            url = self.client.generate_presigned_url(
                'get_object',
                Params={'Bucket': self.bucket, 'Key': s3_key},
                ExpiresIn=expires_in
            )
            return url
        except ClientError:
            return None

    def list_files(self, prefix: str = '') -> list:
        try:
            response = self.client.list_objects_v2(Bucket=self.bucket, Prefix=prefix)
            return [obj['Key'] for obj in response.get('Contents', [])]
        except ClientError:
            return []

