from fastapi import FastAPI, Request, Response, HTTPException
from prometheus_client import Counter, Histogram, Gauge, generate_latest, CONTENT_TYPE_LATEST
import time, random

app = FastAPI()

REQUEST_COUNT = Counter('http_requests_total', 'Total HTTP requests', ['method', 'endpoint', 'status_code'])
REQUEST_LATENCY = Histogram('http_request_duration_seconds', 'Request latency', ['endpoint'], buckets=[0.01, 0.05, 0.1, 0.5, 1.0, 5.0])
REGISTERED_USERS = Gauge('registered_users_total', 'Total registered users')

@app.middleware('http')
async def metrics_middleware(request: Request, call_next):
    start = time.time()
    try:
        response = await call_next(request)
        status = response.status_code
    except Exception as e:
        status = 500
        raise e
    finally:
        duration = time.time() - start
        REQUEST_COUNT.labels(method=request.method, endpoint=request.url.path, status_code=str(status)).inc()
        REQUEST_LATENCY.labels(endpoint=request.url.path).observe(duration)
    return response

@app.get('/metrics')
def get_metrics():
    return Response(generate_latest(), media_type=CONTENT_TYPE_LATEST)

@app.get('/users')
def list_users():
    if random.random() < 0.1:
        raise HTTPException(status_code=500, detail='Server xatosi')
    return {'users': ['Ali', 'Vali', 'Soli']}

@app.post('/users/register')
def register_user(name: str):
    REGISTERED_USERS.inc()
    return {'registered': name}

@app.delete('/users/{user_id}')
def delete_user(user_id: int):
    REGISTERED_USERS.dec()
    return {'deleted': user_id}

