from fastapi import FastAPI, HTTPException, Request
from pydantic import BaseModel, field_validator
from passlib.context import CryptContext
from slowapi import Limiter, _rate_limit_exceeded_handler
from slowapi.util import get_remote_address
import re

app = FastAPI()
limiter = Limiter(key_func=get_remote_address)
app.state.limiter = limiter
app.add_exception_handler(429, _rate_limit_exceeded_handler)
pwd_context = CryptContext(schemes=['bcrypt'], deprecated='auto')
users_db = {}

class RegisterRequest(BaseModel):
    username: str
    password: str
    email: str

    @field_validator('username')
    def validate_username(cls, v):
        if not re.match(r'^[a-zA-Z0-9_]{3,20}$', v):
            raise ValueError('Username: 3-20 belgi, faqat harf/raqam/_')
        return v

    @field_validator('password')
    def validate_password(cls, v):
        if len(v) < 8:
            raise ValueError('Parol kamida 8 belgi bo\'lsin')
        if not re.search(r'\d', v):
            raise ValueError('Parolda kamida 1 raqam bo\'lsin')
        return v

@app.post('/register')
def register(data: RegisterRequest):
    if data.username in users_db:
        raise HTTPException(status_code=400, detail='Username band')
    users_db[data.username] = {
        'password_hash': pwd_context.hash(data.password),
        'email': data.email
    }
    return {'message': 'Muvaffaqiyatli ro\'yxatdan o\'tdingiz'}

@app.post('/login')
@limiter.limit('5/minute')
def login(request: Request, username: str, password: str):
    user = users_db.get(username)
    if not user or not pwd_context.verify(password, user['password_hash']):
        raise HTTPException(status_code=401, detail='Login yoki parol xato')
    return {'message': 'Xush kelibsiz!', 'username': username}

import timeit
from functools import lru_cache
from collections import Counter
from typing import Generator

def word_frequency_slow(text: str) -> dict:
    words = text.lower().split()
    freq = {}
    for word in words:
        freq[word] = freq.get(word, 0) + 1
    return freq

@lru_cache(maxsize=128)
def word_frequency_cached(text: str) -> dict:
    return dict(Counter(text.lower().split()))

def read_lines_generator(filepath: str) -> Generator[str, None, None]:
    with open(filepath, 'r', encoding='utf-8') as f:
        for line in f:
            yield line.strip()

def word_frequency_fast(text: str) -> dict:
    return dict(Counter(text.lower().split()))

def top_words(text: str, n: int = 5) -> list:
    counter = Counter(text.lower().split())
    return counter.most_common(n)

if __name__ == '__main__':
    test_text = 'python is great python is fast python is simple ' * 1000

    slow_time = timeit.timeit(lambda: word_frequency_slow(test_text), number=100)
    fast_time = timeit.timeit(lambda: word_frequency_fast(test_text), number=100)

    # Cache test
    word_frequency_cached(test_text)  # warm up
    cached_time = timeit.timeit(lambda: word_frequency_cached(test_text), number=100)

    print(f'Sekin:    {slow_time:.3f}s')
    print(f'Tez:      {fast_time:.3f}s  ({slow_time/fast_time:.1f}x tez)')
    print(f'Cached:   {cached_time:.5f}s ({slow_time/cached_time:.0f}x tez)')
    print(f'Top 5: {top_words(test_text)}')

