from decimal import Decimal
from dataclasses import dataclass
from typing import TypedDict

class OrderItem(TypedDict):
    amount: Decimal
    name: str
    category: str

TAX_RATES = {
    1: Decimal('0.18'),  # Standard QQS
    2: Decimal('0.12'),  # Imtiyozli QQS
    3: Decimal('0.00'),  # Soliqqmas
}

def is_valid_order_item(item: OrderItem) -> bool:
    return (
        item.get('amount', 0) > 0
        and bool(item.get('name', '').strip())
        and item.get('category') is not None
    )

def apply_tax(amount: Decimal, tax_type: int) -> Decimal:
    rate = TAX_RATES.get(tax_type)
    if rate is None:
        raise ValueError(f'Noma\'lum soliq turi: {tax_type}')
    return amount + (amount * rate)

def calculate_and_save_orders(
    items: list[OrderItem],
    tax_type: int,
    db
) -> int:
    """
    Buyurtmalarni qayta ishlaydi va bazaga saqlaydi.
    Returns: saqlangan buyurtmalar soni
    """
    if tax_type not in TAX_RATES:
        raise ValueError(f'Noma\'lum soliq turi: {tax_type}')

    valid_items = [item for item in items if is_valid_order_item(item)]

    for item in valid_items:
        total = apply_tax(Decimal(str(item['amount'])), tax_type)
        item['total'] = total
        # Parameterized query — SQL injection yo'q
        db.execute(
            'INSERT INTO orders (total, tax_type) VALUES (?, ?)',
            (float(total), tax_type)
        )

    return len(valid_items)
